// ============================================================
// Secure Binding Configuration - Prevents Weak Encryption
// ============================================================

public static class SecureBindingFactory
{
    /// <summary>
    /// Creates a HIPAA-compliant WS-Security binding with strong encryption.
    /// Prevents weak encryption by enforcing AES-256 and SHA-256 minimum.
    /// Uses mutual certificate authentication (message-level security).
    /// </summary>
    public static CustomBinding CreateHipaaCompliantBinding()
    {
        // Start with a secure WSHttpBinding as a base, then customize
        var securityElement = SecurityBindingElement.CreateMutualCertificateBindingElement(
            MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10);

        // ============================================================
        // STRONG ENCRYPTION CONFIGURATION - Prevent Weak Encryption
        // ============================================================

        // Enforce AES-256 for symmetric encryption (prevents DES, 3DES, AES-128)
        securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        // The Basic256Sha256 suite enforces:
        //   - Symmetric Encryption: AES-256-CBC
        //   - Asymmetric Encryption: RSA-OAEP
        //   - Symmetric Signature: HMAC-SHA256
        //   - Asymmetric Signature: RSA-SHA256
        //   - Digest: SHA-256
        //   - Key Derivation: P-SHA256
        //   - Minimum symmetric key length: 256 bits
        //   - Maximum symmetric key length: 256 bits
        //   - Minimum asymmetric key length: 1024 bits (we enforce 2048+ via cert)

        // Enable secure conversation for session-based security
        securityElement.IncludeTimestamp = true;
        securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;

        // Set message protection order - sign then encrypt for maximum security
        securityElement.MessageProtectionOrder = MessageProtectionOrder.SignBeforeEncryptAndEncryptSignature;

        // Require signature confirmation to prevent reflection attacks
        securityElement.RequireSignatureConfirmation = true;

        // Configure key entropy mode
        securityElement.KeyEntropyMode = SecurityKeyEntropyMode.CombinedEntropy;

        // Set reasonable security timestamp tolerances
        securityElement.LocalClientSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
        securityElement.LocalClientSettings.TimestampValidityDuration = TimeSpan.FromMinutes(10);
        securityElement.LocalClientSettings.ReplayWindow = TimeSpan.FromMinutes(5);
        securityElement.LocalClientSettings.DetectReplays = true;

        securityElement.LocalServiceSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
        securityElement.LocalServiceSettings.TimestampValidityDuration = TimeSpan.FromMinutes(10);
        securityElement.LocalServiceSettings.ReplayWindow = TimeSpan.FromMinutes(5);
        securityElement.LocalServiceSettings.DetectReplays = true;

        // Build the custom binding with secure transport
        var binding = new CustomBinding();
        binding.Elements.Add(securityElement);

        // Use MTOM encoding for efficient binary data (medical images, etc.)
        var textEncoding = new TextMessageEncodingBindingElement
        {
            MessageVersion = MessageVersion.Soap12WSAddressing10
        };
        binding.Elements.Add(textEncoding);

        // Use HTTPS transport for defense in depth (TLS + WS-Security)
        var httpsTransport = new HttpsTransportBindingElement
        {
            RequireClientCertificate = true,
            MaxReceivedMessageSize = 67108864, // 64 MB for medical records
            MaxBufferSize = 67108864
        };
        binding.Elements.Add(httpsTransport);

        binding.SendTimeout = TimeSpan.FromMinutes(5);
        binding.ReceiveTimeout = TimeSpan.FromMinutes(10);
        binding.OpenTimeout = TimeSpan.FromMinutes(1);
        binding.CloseTimeout = TimeSpan.FromMinutes(1);

        return binding;
    }

    /// <summary>
    /// Alternative: Creates a binding using WSHttpBinding with strong security settings.
    /// </summary>
    public static WSHttpBinding CreateSecureWsHttpBinding()
    {
        var binding = new WSHttpBinding(SecurityMode.TransportWithMessageCredential)
        {
            MaxReceivedMessageSize = 67108864,
            MaxBufferPoolSize = 67108864,
            ReaderQuotas =
            {
                MaxDepth = 64,
                MaxStringContentLength = 8388608,
                MaxArrayLength = 16384,
                MaxBytesPerRead = 4096,
                MaxNameTableCharCount = 16384
            }
        };

        // Message-level security with certificate credentials
        binding.Security.Message.ClientCredentialType = MessageCredentialType.Certificate;
        binding.Security.Message.EstablishSecurityContext = true;
        binding.Security.Message.NegotiateServiceCredential = false;

        // CRITICAL: Enforce strong algorithm suite - prevents weak encryption
        binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        binding.Security.Transport.ClientCredentialType = HttpClientCredentialType.Certificate;

        return binding;
    }
}

// ============================================================
// Algorithm Suite Validator - Additional Protection Against Weak Crypto
// ============================================================

public static class CryptoValidator
{
    // Blocked weak algorithm suites
    private static readonly HashSet<string> WeakAlgorithmSuites = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "Basic128",
        "Basic192",
        "Basic128Rsa15",
        "Basic192Rsa15",
        "Basic256Rsa15",        // RSA 1.5 padding is vulnerable to Bleichenbacher attacks
        "TripleDes",
        "TripleDesRsa15",
        "TripleDesSha256",      // 3DES has only 112-bit effective security
        "TripleDesSha256Rsa15",
        "Basic128Sha256",       // 128-bit symmetric is below our minimum
        "Basic192Sha256",       // 192-bit symmetric is below our minimum
        "Basic128Sha256Rsa15",
        "Basic192Sha256Rsa15",
        "Basic256Sha256Rsa15"   // RSA 1.5 padding vulnerability
    };

    // Approved strong algorithm suites for HIPAA compliance
    private static readonly HashSet<string> ApprovedAlgorithmSuites = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "Basic256Sha256"        // AES-256 + SHA-256 + RSA-OAEP
    };

    public static bool IsAlgorithmSuiteStrong(SecurityAlgorithmSuite suite)
    {
        if (suite == null) return false;

        // Check minimum symmetric key length (must be 256 bits)
        if (suite.DefaultSymmetricKeyLength < 256)
            return false;

        // Verify it's in our approved list
        string suiteName = suite.ToString();
        if (WeakAlgorithmSuites.Contains(suiteName))
            return false;

        return ApprovedAlgorithmSuites.Contains(suiteName);
    }

    public static void ValidateAlgorithmSuite(SecurityAlgorithmSuite suite)
    {
        if (!IsAlgorithmSuiteStrong(suite))
        {
            throw new SecurityException(
                $"Algorithm suite '{suite}' does not meet HIPAA security requirements. " +
                $"Minimum required: Basic256Sha256 (AES-256 + SHA-256 + RSA-OAEP). " +
                $"Approved suites: {string.Join(", ", ApprovedAlgorithmSuites)}");
        }
    }

    public static void ValidateCertificate(X509Certificate2 certificate)
    {
        if (certificate == null)
            throw new SecurityException("Certificate cannot be null.");

        // Verify minimum RSA key size of 2048 bits
        if (certificate.PublicKey.Key.KeySize < 2048)
        {
            throw new SecurityException(
                $"Certificate RSA key size {certificate.PublicKey.Key.KeySize} bits is below " +
                $"the minimum required 2048 bits for HIPAA compliance.");
        }

        // Verify certificate is not expired
        if (DateTime.UtcNow > certificate.NotAfter || DateTime.UtcNow < certificate.NotBefore)
        {
            throw new SecurityException("Certificate is expired or not yet valid.");
        }

        // Verify signature algorithm is not weak
        string signatureAlgorithm = certificate.SignatureAlgorithm.FriendlyName?.ToUpperInvariant() ?? "";
        if (signatureAlgorithm.Contains("SHA1") || signatureAlgorithm.Contains("MD5"))
        {
            throw new SecurityException(
                $"Certificate signature algorithm '{certificate.SignatureAlgorithm.FriendlyName}' " +
                $"is considered weak. Use SHA-256 or stronger.");
        }
    }
}

