public class HealthcareServiceHost
{
    private ServiceHost _serviceHost;

    public void Start()
    {
        try
        {
            var baseAddress = new Uri("https://localhost:8443/HealthcareRecordService");
            _serviceHost = new ServiceHost(typeof(HealthcareRecordService), baseAddress);

            // Get the secure binding
            CustomBinding secureBinding = SecureBindingFactory.CreateHipaaCompliantBinding();

            // Validate the algorithm suite before starting
            var securityElement = secureBinding.Elements.Find<SecurityBindingElement>();
            if (securityElement != null)
            {
                CryptoValidator.ValidateAlgorithmSuite(securityElement.DefaultAlgorithmSuite);
            }

            // Add the service endpoint
            var endpoint = _serviceHost.AddServiceEndpoint(
                typeof(IHealthcareRecordService),
                secureBinding,
                "");

            // Configure service credentials with certificates
            ConfigureServiceCredentials(_serviceHost);

            // Configure service behaviors
            ConfigureServiceBehaviors(_serviceHost);

            // Add metadata endpoint (secured)
            ConfigureMetadata(_serviceHost, baseAddress);

            _serviceHost.Open();
            Console.WriteLine($"Healthcare Record Service started at {baseAddress}");
            Console.WriteLine("Service is HIPAA-compliant with AES-256-SHA256 encryption.");
            Console.WriteLine("Weak encryption algorithms are blocked.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Failed to start service: {ex.Message}");
            _serviceHost?.Abort();
            throw;
        }
    }

    public void Stop()
    {
        if (_serviceHost != null)
        {
            try
            {
                _serviceHost.Close();
            }
            catch
            {
                _serviceHost.Abort();
            }
        }
    }

    private void ConfigureServiceCredentials(ServiceHost host)
    {
        var credentials = host.Credentials;

        // Service certificate for encryption and signing
        // In production, load from a secure certificate store
        credentials.ServiceCertificate.SetCertificate(
            StoreLocation.LocalMachine,
            StoreName.My,
            X509FindType.FindBySubjectName,
            "HealthcareService");

        // Validate the service certificate meets minimum requirements
        if (credentials.ServiceCertificate.Certificate != null)
        {
            CryptoValidator.ValidateCertificate(credentials.ServiceCertificate.Certificate);
        }

        // Client certificate authentication settings
        credentials.ClientCertificate.Authentication.CertificateValidationMode =
            System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
        credentials.ClientCertificate.Authentication.RevocationMode =
            X509RevocationMode.Online;

        // Peer trust for the service certificate
        credentials.Peer.PeerAuthentication.CertificateValidationMode =
            System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
    }

    private void ConfigureServiceBehaviors(ServiceHost host)
    {
        var debugBehavior = host.Description.Behaviors.Find<ServiceDebugBehavior>();
        if (debugBehavior == null)
        {
            debugBehavior = new ServiceDebugBehavior();
            host.Description.Behaviors.Add(debugBehavior);
        }
        // Never include exception details in production (HIPAA: minimize data exposure)
        debugBehavior.IncludeExceptionDetailInFaults = false;

        var throttleBehavior = new ServiceThrottlingBehavior
        {
            MaxConcurrentCalls = 100,
            MaxConcurrentInstances = 100,
            MaxConcurrentSessions = 100
        };
        host.Description.Behaviors.Add(throttleBehavior);

        // Configure service authorization
        var authBehavior = host.Description.Behaviors.Find<ServiceAuthorizationBehavior>();
        if (authBehavior == null)
        {
            authBehavior = new ServiceAuthorizationBehavior();
            host.Description.Behaviors.Add(authBehavior);
        }
        authBehavior.PrincipalPermissionMode = PrincipalPermissionMode.UseWindowsGroups;
    }

    private void ConfigureMetadata(ServiceHost host, Uri baseAddress)
    {
        var metadataBehavior = host.Description.Behaviors.Find<ServiceMetadataBehavior>();
        if (metadataBehavior == null)
        {
            metadataBehavior = new ServiceMetadataBehavior();
            host.Description.Behaviors.Add(metadataBehavior);
        }
        // Only HTTPS metadata in production
        metadataBehavior.HttpGetEnabled = false;
        metadataBehavior.HttpsGetEnabled = true;
        metadataBehavior.HttpsGetUrl = new Uri(baseAddress + "/mex");
    }
}

