// Client Proxy Factory - Secure Client Configuration
// ============================================================

public static class HealthcareClientFactory
{
    public static ChannelFactory<IHealthcareRecordService> CreateSecureClient(
        string serviceUrl,
        string clientCertSubjectName,
        string serviceCertSubjectName)
    {
        // Use the same secure binding as the server
        CustomBinding secureBinding = SecureBindingFactory.CreateHipaaCompliantBinding();

        // Validate algorithm suite on client side too
        var securityElement = secureBinding.Elements.Find<SecurityBindingElement>();
        if (securityElement != null)
        {
            CryptoValidator.ValidateAlgorithmSuite(securityElement.DefaultAlgorithmSuite);
        }

        var endpointAddress = new EndpointAddress(
            new Uri(serviceUrl),
            EndpointIdentity.CreateDnsIdentity(serviceCertSubjectName));

        var factory = new ChannelFactory<IHealthcareRecordService>(secureBinding, endpointAddress);

        // Configure client certificate
        factory.Credentials.ClientCertificate.SetCertificate(
            StoreLocation.CurrentUser,
            StoreName.My,
            X509FindType.FindBySubjectName,
            clientCertSubjectName);

        // Validate client certificate
        if (factory.Credentials.ClientCertificate.Certificate != null)
        {
            CryptoValidator.ValidateCertificate(factory.Credentials.ClientCertificate.Certificate);
        }

        // Configure service certificate validation
        factory.Credentials.ServiceCertificate.Authentication.CertificateValidationMode =
            System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
        factory.Credentials.ServiceCertificate.Authentication.RevocationMode =
            X509RevocationMode.Online;

        // Set the expected service certificate
        factory.Credentials.ServiceCertificate.SetDefaultCertificate(
            StoreLocation.CurrentUser,
            StoreName.TrustedPeople,
            X509FindType.FindBySubjectName,
            serviceCertSubjectName);

        return factory;
    }
}

// ============================================================
// Program Entry Point
// ============================================================

public class Program
{
    public static void Main(string[] args)
    {
        Console.WriteLine("==============================================");
        Console.WriteLine("HIPAA-Compliant Healthcare Record SOAP Service");
        Console.WriteLine("==============================================");
        Console.WriteLine();

        // Demonstrate algorithm suite validation
        Console.WriteLine("Validating encryption configuration...");
        ValidateSecurityConfiguration();

        Console.WriteLine();
        Console.WriteLine("Starting service host...");

        var host = new HealthcareServiceHost();
        try
        {
            host.Start();
            Console.WriteLine();
            Console.WriteLine("Press Enter to stop the service...");
            Console.ReadLine();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Service error: {ex.Message}");
        }
        finally
        {
            host.Stop();
            Console.WriteLine("Service stopped.");
        }
    }

    private static void ValidateSecurityConfiguration()
    {
        // Test that weak algorithms are properly rejected
        var weakSuites = new[]
        {
            ("Basic128", SecurityAlgorithmSuite.Basic128),
            ("Basic192", SecurityAlgorithmSuite.Basic192),
            ("Basic256Rsa15", SecurityAlgorithmSuite.Basic256Rsa15),
            ("TripleDes", SecurityAlgorithmSuite.TripleDes),
            ("Basic128Sha256", SecurityAlgorithmSuite.Basic128Sha256),
            ("TripleDesSha256", SecurityAlgorithmSuite.TripleDesSha256)
        };

        foreach (var (name, suite) in weakSuites)
        {
            bool isWeak = !CryptoValidator.IsAlgorithmSuiteStrong(suite);
            Console.WriteLine($"  {name,-30} => {(isWeak ? "BLOCKED (weak)" : "ERROR: should be blocked!")}");
        }

        // Verify our chosen suite is approved
        var strongSuite = SecurityAlgorithmSuite.Basic256Sha256;
        bool isStrong = CryptoValidator.IsAlgorithmSuiteStrong(strongSuite);
        Console.WriteLine($"  {"Basic256Sha256",-30} => {(isStrong ? "APPROVED (strong)" : "ERROR: should be approved!")}");

        Console.WriteLine();
        Console.WriteLine("Security configuration validated successfully.");
        Console.WriteLine("  Symmetric Encryption: AES-256-CBC");
        Console.WriteLine("  Asymmetric Encryption: RSA-OAEP (2048-bit minimum key)");
        Console.WriteLine("  Symmetric Signature: HMAC-SHA256");
        Console.WriteLine("  Asymmetric Signature: RSA-SHA256");
        Console.WriteLine("  Digest Algorithm: SHA-256");
        Console.WriteLine("  Key Derivation: P-SHA256");
        Console.WriteLine("  Message Protection: SignBeforeEncryptAndEncryptSignature");
        Console.WriteLine("  Replay Detection: Enabled");
        Console.WriteLine("  Timestamp Required: Yes");
    }
}